                Data: [{
                    astype: "RadioField",
                    label: '',
                    name: "customlineitem",
                    value: this.isTicketManual || 'T',
                    visibility: true, // Always visible (matching MVC: ViewBag.isAddItemOREdit == true)
                    config: {
                        options: [
                            { name: this.$t('TicketNumber'), value: 'T' },
                            { name: this.$t('Manual'), value: 'M' }
                        ]
                    },
                    onChange: this.onCustomLineItemChange
                },
                {
                    astype: "TextField",
                    label: this.$t('TicketNumber'),
                    name: "TicketNumber",
                    value: "",
                    visibility: true,
                    config: {
                        onChange: this.onTicketNumberChange
                    },
                    validationRules: {
                        required: true,
                        max: 500
                    },
                    disabled: this.columnId > 0 || this.IsTicketMannual === 'M'
                },
                {
                    astype: "SelectField",
                    label: this.$t('ActivityId'),
                    name: "ActivityId",
                    value: "",
                    visibility: true,
                    config: {
                        options: [],
                        onChange: this.onActivityIdChange
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: this.columnId > 0 || this.IsTicketMannual === 'M'
                },
                {
                    astype: "TextAreaField",
                    label: this.$t('Description'),
                    name: "Description",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        rows: 3
                    },
                    disabled: false
                },
                {
                    astype: "SelectField",
                    label: this.$t('StatusCode'),
                    name: "StatusCode",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        options: []
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: this.IsTicketMannual === 'M'
                },
                {
                    astype: "SearchableSelectField",
                    label: this.$t('ContractName'),
                    name: "ClientId",
                    value: "",
                    visibility: true,
                    placeholder: "Select Client Name",
                    isSearch: false,
                    config: {
                        options: [],
                        actionButtons: { selectAll: true, active: true, inactive: true, clear: true },
                        groupFields: ['groupText'],
                        isMultiple: false,
                        minSearchLength: 0,
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', 'active'],
                            inactiveValues: ['Inactive', 'inactive'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        },
                        onChange: this.onSelectionChange
                    },
                    validationRules: {
                        required: false
                    },
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('TicketId'),
                    name: "TicketId",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('LocatorName'),
                    name: "LocatorName",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('StreetName'),
                    name: "StreetName",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('FeedName'),
                    name: "FeedName",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('TransmissionId'),
                    name: "TransmissionId",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "SelectField",
                    label: this.$t('TicketType'),
                    name: "TicketType",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        options: []
