                    disabled: this.IsTicketMannual === 'M'
                },
                {
                    astype: "TextField",
                    label: this.$t('WorkArea'),
                    name: "WorkArea",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "DateField",
                    label: this.$t('CallDate'),
                    name: "CallDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('TransmitDate'),
                    name: "TransmitDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('LocatorStartDate'),
                    name: "LocatorStartDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('ParseDate'),
                    name: "ParseDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "TextField",
                    label: this.$t('County'),
                    name: "County",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('State'),
                    name: "State",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('CallerName'),
                    name: "CallerName",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('CallerPhone'),
                    name: "CallerPhone",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('WorkDoneFor'),
                    name: "WorkDoneFor",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('Excavator'),
                    name: "Excavator",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('TypeofWork'),
                    name: "TypeOfWork",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "DateField",
                    label: this.$t('LocatorEndDate'),
                    name: "LocatorEndDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('InitialStatusDate'),
                    name: "InitialStatusDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('LegalDuedate'),
                    name: "LegalDuedate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "DateField",
                    label: this.$t('TicketStartDate'),
                    name: "TicketStartDate",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "TextField",
                    label: this.$t('UtilityName'),
                    name: "UtilityName",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "NumericField",
                    label: this.$t('FeetLocated'),
                    name: "FeetLocated",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false,
                    onKeyUp: this.calculateNetTotal
                },
                {
                    astype: "NumericField",
                    label: this.$t('MinutesWorked'),
                    name: "MinutesWorked",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: false
                },
                {
                    astype: "TextField",
                    label: this.$t('Emergency'),
                    name: "Emergency",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "SlotField",
                    label: this.$t('TicketImage'),
                    name: "TicketImage",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M'
                },
                {
                    astype: "TextAreaField",
                    label: this.$t('Comment'),
                    name: "Comment",
                    value: "",
                    config: {
                        rows: 3
                    }
                },
                {
                    astype: "SelectField",
                    label: this.$t('Utlityid'),
                    name: "UtilityId",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        options: [],
                        onChange: this.onSelectionUtilityChange
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: true
                    //disabled: this.IsTicketMannual === 'M'
                },
                {
                    astype: "SelectField",
                    label: this.$t('sba_id'),
                    name: "SbaId",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        options: []
                    },
                    validationRules: {
                        required: false
                    },
                    disabled: this.IsTicketMannual === 'M'
                },
                // Billing fields
                {
                    astype: "SelectField",
                    label: this.$t('CostCenters'),
                    name: "DistrictCode",
                    value: "",
                    visibility: true,
                    config: {
                        options: []
                    },
                    validationRules: {
                        required: true
                    }
                },
                {
                    astype: "SelectField",
                    label: this.$t('WorkCode'),
                    name: "WorkCodeId",
                    value: "",
                    visibility: true,
                    config: {
                        options: [],
                        onChange: this.onWorkCodeChange
                    },
                    validationRules: {
                        required: false
                    },
                },
                {
                    astype: "SelectField",
                    label: this.$t('Division'),
                    name: "DivisionId",
                    value: "",
                    visibility: true,
                    config: {
                        options: []
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: true
                },
                // Manual fields (shown when Manual selected)
                {
                    astype: "NumericField",
                    label: this.$t('UnitRate'),
                    name: "UnitRate",
                    value: "",
                    visibility: false,
                    validationRules: {
                        required: true
                    },
                    config: {
                        onKeyUp: this.calculateNetTotalManual,
                        onInput: this.calculateNetTotalManual,
                        onChange: this.calculateNetTotalManual
                    },
                    onKeyUp: this.calculateNetTotalManual,
                    onInput: this.calculateNetTotalManual,
                    onChange: this.calculateNetTotalManual
                },
                {
                    astype: "NumericField",
                    label: this.$t('UnitQuantity'),
                    name: "UnitQuantity",
                    value: "",
                    visibility: false,
                    validationRules: {
                        required: true
                    },
                    config: {
                        onKeyUp: this.calculateNetTotalManual,
                        onInput: this.calculateNetTotalManual,
                        onChange: this.calculateNetTotalManual
                    },
                    onKeyUp: this.calculateNetTotalManual,
                    onInput: this.calculateNetTotalManual,
                    onChange: this.calculateNetTotalManual
                },
                {
                    astype: "TextField",
                    label: this.$t('NetTotal'),
                    name: "NetTotalManual",
                    value: "0.00",
                    visibility: false,
                    disabled: false
                },
                // Rate field (shown when editing existing item)
                {
                    astype: "NumericField",
                    label: this.$t('Rate'),
                    name: "UnitAmountTotal",
                    value: "",
                    visibility: this.columnId != 0 && this.columnId != null,
                    onKeyUp: this.calculateNetTotal
                },
                {
                    astype: "TextField",
                    label: this.$t('TermCode'),
                    name: "TermCode",
                    value: "",
                    visibility: true,
                    disabled: true
                },
                {
                    astype: "SelectField",
                    label: this.$t('AdderName'),
                    name: "AdderNameLineItem",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    config: {
                        options: []
                    },
                    disabled: true,
                    onChange: this.onAdderNameChange
                },
                {
                    astype: "NumericField",
                    label: this.$t('AdderUnitCost'),
                    name: "AdderUnitCost",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: this.IsTicketMannual === 'M' || this.AdderUnit <= 0,
                    onKeyUp: this.calculateNetTotal
                },
                {
                    astype: "TextField",
                    label: this.$t('AdderUnit'),
                    name: "AdderUnit",
                    value: "",
                    visibility: this.IsTicketMannual !== 'M',
                    disabled: true
                },
                {
                    astype: "TextField",
                    label: this.$t('NetTotal'),
                    name: "NetTotal",
                    value: "",
                    visibility: true,
                    disabled: true
                }
                ],
            },],
            buttons: [{
                type: "submit",
                class: "btn btn-info",
                text: "<i class='fa fa-plus pr-2'></i>Save & New",
            },
            {
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-save pr-2'></i>Save And Close",
            },
            {
                type: "submit",
                class: "btn btn-primary",
                text: "<i class='fa fa-save pr-2'></i>Save And Reprocess",

            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.Close,
            },
            ],

        }
    },
    created: async function () {
        var vm = this;

        await vm.GetStatusCodes();
        await vm.GetTicketTypes();
        await vm.GetWorkCodeData();
        await vm.GetCostCenters();
        await vm.fetchclientlist();
        if (vm.clientId) {
            await vm.GetDivisionDropdownData();
            await vm.LoadAdditionalInfoByClientId();
        }
        // Check if we're in edit mode - need at least one of lineItemId or columnId
        // For manual items, columnId might be 0, so check if either exists
        var hasLineItemId = vm.lineItemId != null && vm.lineItemId !== '' && vm.lineItemId !== 0 && vm.lineItemId !== '0';
        var hasColumnId = vm.columnId != null && vm.columnId !== '' && vm.columnId !== 0 && vm.columnId !== '0';
        var isEditMode = hasLineItemId || hasColumnId;
        if (isEditMode) {
            // Show radio buttons in edit mode (matching MVC: ViewBag.isAddItemOREdit == true)
            await vm.$nextTick();
            if (vm.$refs.dynamicform) {
                // Keep radio buttons visible in edit mode
                vm.$refs.dynamicform.updateProperty("customlineitem", "visibility", true);
                vm.$refs.dynamicform.UpdateKeyValue();
            }
            await vm.GetInvoiceLineItem();
        } else {
            // For new items, set default values
            await vm.$nextTick();

            // Set default radio button to "Ticket Number" for new items
            if (vm.$refs.dynamicform) {
                vm.IsTicketMannual = 'T';
                vm.$refs.dynamicform.updateProperty("customlineitem", "value", 'T');
            }

            // Set ClientId (Contract Name) if available
            if (vm.clientId && vm.$refs.dynamicform) {
                vm.$refs.dynamicform.updateProperty("ClientId", "value", vm.clientId);
            }

            // Set DivisionId (Invoice Grouping) if available
            if (vm.divisionId && vm.$refs.dynamicform) {
                vm.$refs.dynamicform.updateProperty("DivisionId", "value", vm.divisionId);
            }

            // Set default AdderName to first work code (usually "Additional Footage")
            if (vm.$refs.dynamicform) {
                var workCodeOptions = vm.FormSchema[0].Data.find(f => f.name === "AdderNameLineItem");
                if (workCodeOptions && workCodeOptions.config && workCodeOptions.config.options && workCodeOptions.config.options.length > 0) {
                    var firstWorkCode = workCodeOptions.config.options[0];
                    if (firstWorkCode && firstWorkCode.value) {
                        vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "value", firstWorkCode.value);
                    }
                }
            }

            // Set default AdderUnit to 0.000
            if (vm.$refs.dynamicform) {
                vm.$refs.dynamicform.updateProperty("AdderUnit", "value", "0.000");
                vm.AdderUnit = 0;
            }

            // Set default NetTotal to 0.000
            if (vm.$refs.dynamicform) {
                vm.$refs.dynamicform.updateProperty("NetTotal", "value", "0.000");
            }

            // Load ActivityId dropdown if ticket number is available
            if (vm.billId) {
                // Set TicketNumber if billId is provided
                vm.$refs.dynamicform.updateProperty("TicketNumber", "value", vm.billId);
                await vm.GetActivityIdDropdownListByTicketNumber();
            }

            // Initialize field visibility for add mode - default to Ticket Number
            await vm.$nextTick();
            vm.ShowInvoiceFieldData(vm.isTicketManual, vm.ticketType);

            // Emit loaded event for new items (no async data loading needed)
            vm.$emit('loaded');
        }

        // Update button visibility
        await vm.$nextTick();
        vm.updateButtonVisibility();

    },
    mounted: function () {
        var vm = this;
        // Ensure onChange handlers are properly bound after component is mounted
        vm.$nextTick(() => {
            if (vm.$refs.dynamicform) {
                // Re-bind onChange for UtilityId if needed
                var utilityField = vm.FormSchema[0].Data.find(f => f.name === "UtilityId");
                if (utilityField && utilityField.config) {
                    utilityField.config.onChange = vm.onSelectionUtilityChange;
                }

                // Re-bind onChange for customlineitem (radio buttons) if needed
                var radioField = vm.FormSchema[0].Data.find(f => f.name === "customlineitem");
                if (radioField && radioField.config) {
                    radioField.config.onChange = vm.onCustomLineItemChange;
                }

                // Re-bind onChange for WorkCodeId if needed
                // var workCodeField = vm.FormSchema[0].Data.find(f => f.name === "WorkCodeId");
                // if (workCodeField && workCodeField.config) {
                //     workCodeField.config.onChange = vm.onWorkCodeChange;
                // }

                // Ensure radio button value is set correctly
                if (vm.isAdd && (!vm.columnId || vm.columnId == 0)) {
                    vm.$refs.dynamicform.updateProperty("customlineitem", "value", vm.IsTicketMannual || 'T');
                }

                // Re-bind event handlers for calculation functions
                var unitRateField = vm.FormSchema[0].Data.find(f => f.name === "UnitRate");
                if (unitRateField) {
                    unitRateField.onKeyUp = vm.calculateNetTotalManual;
                    unitRateField.onInput = vm.calculateNetTotalManual;
                    unitRateField.onChange = vm.calculateNetTotalManual;
                    if (!unitRateField.config) {
                        unitRateField.config = {};
                    }
                    unitRateField.config.onKeyUp = vm.calculateNetTotalManual;
                    unitRateField.config.onInput = vm.calculateNetTotalManual;
                    unitRateField.config.onChange = vm.calculateNetTotalManual;
                }

                var unitQuantityField = vm.FormSchema[0].Data.find(f => f.name === "UnitQuantity");
                if (unitQuantityField) {
                    unitQuantityField.onKeyUp = vm.calculateNetTotalManual;
                    unitQuantityField.onInput = vm.calculateNetTotalManual;
                    unitQuantityField.onChange = vm.calculateNetTotalManual;
                    if (!unitQuantityField.config) {
                        unitQuantityField.config = {};
                    }
                    unitQuantityField.config.onKeyUp = vm.calculateNetTotalManual;
                    unitQuantityField.config.onInput = vm.calculateNetTotalManual;
                    unitQuantityField.config.onChange = vm.calculateNetTotalManual;
                }

                var feetLocatedField = vm.FormSchema[0].Data.find(f => f.name === "FeetLocated");
                if (feetLocatedField) {
                    feetLocatedField.onKeyUp = vm.calculateNetTotal;
                }

                var unitAmountTotalField = vm.FormSchema[0].Data.find(f => f.name === "UnitAmountTotal");
                if (unitAmountTotalField) {
                    unitAmountTotalField.onKeyUp = vm.calculateNetTotal;
                }

                var adderUnitCostField = vm.FormSchema[0].Data.find(f => f.name === "AdderUnitCost");
                if (adderUnitCostField) {
                    adderUnitCostField.onKeyUp = vm.calculateNetTotal;
                }

                vm.$refs.dynamicform.UpdateKeyValue();
            }
        });
    },
    watch: {
        UtilityId: {
            handler: function (newVal, oldVal) {
                // Only trigger if value actually changed (not initial load)
                if (newVal && newVal !== oldVal) {
                    this.GetSbaIdListByUtilityId(newVal);
                }
            },
            immediate: false
        }
    },
    methods: {
        Close: function () {
