        GetInvoiceLineItem: async function () {
            debugger
            var vm = this;
            vm.isLoading = true;
            // Validate that we have at least lineItemId or columnId
            if (!vm.lineItemId && !vm.columnId) {
                console.warn('GetInvoiceLineItem: Both lineItemId and columnId are missing, cannot fetch line item');
                vm.isLoading = false;
                return;
            }
            var url = `lineBatchId=${vm.lineBatchId || ''}&billID=${vm.billId || 0}&lineItemId=${vm.lineItemId || 0}&columnId=${vm.columnId || 0}&ticketType=${vm.ticketType || ''}&isTicketMannual=${vm.isTicketManual || ''}`;
            try {
                var response = await locateBillingService.GetInvoiceLineItem(url);

                if (response && response.data && response.data.length > 0) {
                    var item = response.data[0];

                    // Store component data
                    vm.UtilityId = item.CLIENT_ADDITIONAL_ID || '';
                    vm.ActivityId = item.ACTIVITY_ID || '';
                    vm.SbaId = item.BE_SBA_ID || item.SBA_ID || '';

                    // Normalize IsTicketMannual value - ensure it's 'M' or 'T' (matching MVC behavior)
                    var isTicketManualValue = item.IS_MANNUAL;
                    if (isTicketManualValue === 'M' || isTicketManualValue === 'Manual' || isTicketManualValue === true || isTicketManualValue === 1 || isTicketManualValue === '1') {
                        vm.IsTicketMannual = 'M';
                    } else if (isTicketManualValue === 'T' || isTicketManualValue === 'Ticket' || isTicketManualValue === false || isTicketManualValue === 0 || isTicketManualValue === '0' || isTicketManualValue === null || isTicketManualValue === undefined) {
                        vm.IsTicketMannual = 'T';
                    } else {
                        // Default to 'T' if value is not recognized
                        vm.IsTicketMannual = 'T';
                    }
                    vm.isTicketManual = vm.IsTicketMannual; // Sync with prop
                    vm.ticketType = item.TICKETTYPE || vm.ticketType;
                    vm.AdderUnit = parseFloat(item.ADDER_UNIT || 0);

                    // Step 1: Set ClientId first to load dependent dropdowns (matching MVC behavior)
                    if (item.CLIENT_ID) {
                        vm.clientId = item.CLIENT_ID;
                        vm.$refs.dynamicform.updateProperty("ClientId", "value", item.CLIENT_ID);

                        // Load DivisionId and UtilityId dropdowns based on ClientId (matching MVC: ShowUtlitityNamesDropDown, ShowSbaIdsDropDown)
                        await vm.GetDivisionDropdownData(item.CLIENT_ID);
                        await vm.LoadAdditionalInfoByClientId(item.CLIENT_ID);
                    }

                    // Step 2: Set TicketNumber and load ActivityId dropdown (matching MVC: $("#TicketNumber").blur)
                    var ticketNumber = item.TICKETNUMBER || vm.billId || '';
                    vm.$refs.dynamicform.updateProperty("TicketNumber", "value", ticketNumber);
                    if (ticketNumber && item.CLIENT_ID) {
                        await vm.GetActivityIdDropdownListByTicketNumber(ticketNumber, item.CLIENT_ID);
                    }

                    // Step 3: Set radio button value FIRST, then show/hide fields, then set field values
                    // This ensures fields are visible before we try to set their values
                    await vm.$nextTick();

                    // Set radio button value based on normalized IsTicketMannual
                    var radioValue = (vm.IsTicketMannual === 'M') ? 'M' : 'T';
                    vm.$refs.dynamicform.updateProperty("customlineitem", "value", radioValue);
                    vm.$refs.dynamicform.updateProperty("customlineitem", "visibility", true);
                    vm.isTicketManual = radioValue; // Sync with prop
                    vm.$refs.dynamicform.UpdateKeyValue();

                    // Wait for radio button to update
                    await vm.$nextTick();
                    await new Promise(resolve => setTimeout(resolve, 50));

                    // Show/hide fields based on radio button selection BEFORE setting values
                    vm.ShowInvoiceFieldData(radioValue, item.TICKETTYPE);
                    vm.updateButtonVisibility();

                    // Wait for fields to be shown/hidden
                    await vm.$nextTick();
                    await new Promise(resolve => setTimeout(resolve, 100));

                    // Step 4: Now set all text field values (fields are now visible/hidden correctly)
                    // Only set ticket field values if NOT in manual mode
                    if (radioValue !== 'M') {
                        vm.$refs.dynamicform.updateProperty("Description", "value", item.DESCRIPTION || '');
                        vm.$refs.dynamicform.updateProperty("TicketId", "value", item.TICKET_ID || '');
                        vm.$refs.dynamicform.updateProperty("LocatorName", "value", item.LOCATOR_NAME || '');
                        vm.$refs.dynamicform.updateProperty("StreetName", "value", item.STREETNAME || '');
                        vm.$refs.dynamicform.updateProperty("FeedName", "value", item.FEEDNAME || '');
                        vm.$refs.dynamicform.updateProperty("TransmissionId", "value", item.TRANSMISSION_ID || '');
                        vm.$refs.dynamicform.updateProperty("WorkArea", "value", item.WORK_AREA || '');
                        vm.$refs.dynamicform.updateProperty("CallDate", "value", vm.formatDateForDisplay(item.CALL_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("TransmitDate", "value", vm.formatDateForDisplay(item.TRANSMIT_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("LocatorStartDate", "value", vm.formatDateForDisplay(item.WORK_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("ParseDate", "value", vm.formatDateForDisplay(item.PARSE_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("County", "value", item.COUNTY || '');
                        vm.$refs.dynamicform.updateProperty("State", "value", item.STATE || '');
                        vm.$refs.dynamicform.updateProperty("CallerName", "value", item.CALLER_NAME || '');
                        vm.$refs.dynamicform.updateProperty("CallerPhone", "value", item.CALLER_PHONE || '');
                        vm.$refs.dynamicform.updateProperty("WorkDoneFor", "value", item.WORK_DONE_FOR || '');
                        vm.$refs.dynamicform.updateProperty("Excavator", "value", item.EXCAVATOR || '');
                        vm.$refs.dynamicform.updateProperty("TypeOfWork", "value", item.TYPEOFWORK || '');
                        vm.$refs.dynamicform.updateProperty("LocatorEndDate", "value", vm.formatDateForDisplay(item.CLOSED_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("InitialStatusDate", "value", vm.formatDateForDisplay(item.INITIAL_STATUS_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("LegalDuedate", "value", vm.formatDateForDisplay(item.LEGAL_DUE_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("TicketStartDate", "value", vm.formatDateForDisplay(item.OUR_DUE_DATE) || '');
                        vm.$refs.dynamicform.updateProperty("UtilityName", "value", item.UTILITY_NAME || '');
                        vm.$refs.dynamicform.updateProperty("FeetLocated", "value", item.FEET_LOCATED || '');
                        vm.$refs.dynamicform.updateProperty("MinutesWorked", "value", item.MINUTES_WORKED || '');
                        vm.$refs.dynamicform.updateProperty("Emergency", "value", item.EMERGENCY || '');
                    }
                    // Comment field can be set for both modes
                    vm.$refs.dynamicform.updateProperty("Comment", "value", item.REMARKS || '');
                    // Set manual-specific fields (UnitRate, UnitQuantity, NetTotalManual) for manual items
                    if (radioValue === 'M') {
                        // Format and set UnitRate
                        if (item.UNIT_RATE != null && item.UNIT_RATE !== '') {
                            var unitRateValue = parseFloat(item.UNIT_RATE).toFixed(2);
                            vm.$refs.dynamicform.updateProperty("UnitRate", "value", unitRateValue);
                        } else {
                            vm.$refs.dynamicform.updateProperty("UnitRate", "value", '');
                        }

                        // Format and set UnitQuantity
                        if (item.UNIT_WORKED != null && item.UNIT_WORKED !== '') {
                            var unitQuantityValue = parseFloat(item.UNIT_WORKED).toFixed(2);
                            vm.$refs.dynamicform.updateProperty("UnitQuantity", "value", unitQuantityValue);
                        } else {
                            vm.$refs.dynamicform.updateProperty("UnitQuantity", "value", '');
                        }

                        // Calculate and set NetTotalManual
                        if (item.UNIT_RATE != null && item.UNIT_RATE !== '' && item.UNIT_WORKED != null && item.UNIT_WORKED !== '') {
                            var netTotalManual = parseFloat(item.UNIT_RATE || 0) * parseFloat(item.UNIT_WORKED || 0);
