                    vm.$refs.dynamicform.UpdateKeyValue();
                    await vm.$nextTick();
                    await new Promise(resolve => setTimeout(resolve, 50));

                    // Step 5: Set dropdown values (options should already be loaded) - matching MVC: $("select#TicketType").val("@Model.TicketType")
