                    await vm.$nextTick();
                    await new Promise(resolve => setTimeout(resolve, 200));

                    // Set dropdown values after options are loaded - IMPORTANT: Set these values AFTER fields are visible
                    // Set Cost Center (DistrictCode) - CRITICAL for manual items
                    if (item.DISTRICT_CODE) {
                        vm.$refs.dynamicform.updateProperty("DistrictCode", "value", item.DISTRICT_CODE);
                    }

                    // Set Work Code - CRITICAL for manual items
                    // For flat fee, set WorkCodeId to "FF" (matching MVC: $('select#WorkCodeId option').map(function () { if ($(this).text() == "FF") return this; }).attr('selected', 'selected'))
                    if (item.TICKETTYPE === 'F') {
                        // Find and set "FF" work code
                        var workCodeOptions = vm.$refs.dynamicform.getPropertyValue("WorkCodeId", "config.options") || [];
                        var ffWorkCode = workCodeOptions.find(opt => opt.name === "FF" || opt.text === "FF");
