            // Convert dateOfInvoice to string if it's a Date object
            var dateOfInvoiceStr = '';
            if (vm.dateOfInvoice) {
                if (vm.dateOfInvoice instanceof Date) {
                    dateOfInvoiceStr = vm.dateOfInvoice.toISOString().split('T')[0];
                } else {
                    dateOfInvoiceStr = vm.dateOfInvoice.toString();
                }
            }

            var postData = {
                columnId: vm.columnId || "0",
                SetupId: "",
                BatchId: vm.batchId || "",
                LineBatchId: vm.lineBatchId || vm.batchId || "",
                BillId: vm.billId || "",
                IsAdd: vm.isAdd,
                IsReadOnlyForReport: "",
                IsTicketMannual: vm.isTicketManual,
                IsTicketFlatFee: vm.ticketType,
                customlineitem: vm.isTicketManual,
                LineItemId: vm.lineItemId || "0",
                isProcessed: 1,
                DateOfInvoiceLine: dateOfInvoiceStr,
                InvoiceBatchId: vm.batchId || "",
                RecordOnSearchTicketNumer: "yes",
                TicketNumber: formfields.TicketNumber,
                ActivityId: formfields.ActivityId,
                Description: formfields.Description,
                Status: formfields.StatusCode || formfields.Status,
                ClientId: formfields.ClientId,
                TicketId: formfields.TicketId,
                LocatorName: formfields.LocatorName,
                StreetName: formfields.StreetName,
                FeedName: formfields.FeedName,
                TransmissionId: formfields.TransmissionId,
                TicketType: formfields.TicketType,
                WorkArea: formfields.WorkArea,
                CallDate: formfields.CallDate,
                TransmitDate: formfields.TransmitDate,
                WorkDate: formfields.LocatorStartDate,
                ParseDate: formfields.ParseDate,
                County: formfields.County,
                State: formfields.State,
                CallerName: formfields.CallerName,
                CallerPhone: formfields.CallerPhone,
                WorkDoneFor: formfields.WorkDoneFor,
                Excavator: formfields.Excavator,
                TypeOfWork: formfields.TypeOfWork,
                ClosedDate: formfields.LocatorEndDate,
                InitialStatusDate: formfields.InitialStatusDate,
                LegalDuedate: formfields.LegalDuedate,
                OurDueDate: formfields.TicketStartDate,
                UtilityName: formfields.UtilityName,
                FeetLocated: formfields.FeetLocated,
                MinutesWorked: formfields.MinutesWorked,
                Emergency: formfields.Emergency,
                Comment: formfields.Comment,
                ClientAdditionalId: formfields.UtilityId,
                SbaId: formfields.SbaId,
                DistrictCode: formfields.DistrictCode,
                WorkCodeId: formfields.WorkCodeId,
                DivisionId: formfields.DivisionId,
                UnitRate: formfields.UnitRate,
                UnitQuantity: formfields.UnitQuantity,
                UnitAmountTotal: formfields.UnitAmountTotal,
                TermCode: formfields.TermCode,
                AdderNameLineItem: formfields.AdderNameLineItem,
                AdderUnitCost: formfields.AdderUnitCost,
                AdderUnit: formfields.AdderUnit,
                NetTotal: formfields.NetTotal,
                ProcessLogJson: ProcessLogJson,
                newStringifyModel: JSON.stringify(formfields),
                oldStringifyModel: JSON.stringify(vm.oldValues || {}),
                isSaveClicked: isSaveClicked
            };

            locateBillingService.UpdateInvoiceLineItem(postData).then(response => {
                vm.isLoading = false;
                if (response.data && response.data.msg === "Success") {
                    vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                    if (isSaveClicked == 1 || isSaveClicked == 0) {
                        // vm.$emit('saved', { buttonName: buttonName });
                        if (buttonName !== 'Save & New') {
                            vm.Close();
                        } else {

                            if (vm.isTicketManual === 'M') {

                                //vm.$refs.dynamicform.resetForm();
                                vm.$refs.dynamicform.updateProperty("DistrictCode", "value", "");
                                vm.$refs.dynamicform.updateProperty("WorkCodeId", "value", "");
                                vm.$refs.dynamicform.updateProperty("UnitRate", "value", "");
                                vm.$refs.dynamicform.updateProperty("UnitQuantity", "value", "");
                                vm.$refs.dynamicform.updateProperty("TermCode", "value", "");
                                vm.$refs.dynamicform.updateProperty("NetTotalManual", "value", "0.00");

                                vm.oldValues = {};

                                vm.IsTicketMannual = 'M';
                                vm.$refs.dynamicform.updateProperty("customlineitem", "value", 'M');
                                vm.$nextTick(() => {
                                    vm.ShowInvoiceFieldData('M', vm.ticketType);

                                    if (vm.clientId) {
                                        vm.$refs.dynamicform.updateProperty("ClientId", "value", vm.clientId);
                                    }
                                    if (vm.divisionId) {
                                        vm.$refs.dynamicform.updateProperty("DivisionId", "value", vm.divisionId);
                                    }
                                    if (vm.billId) {
                                        vm.$refs.dynamicform.updateProperty("TicketNumber", "value", vm.billId);
                                    }
                                });
                            }
                            else {

                                vm.oldValues = {};

                                // Clear all fields in FormSchema
                                vm.FormSchema[0].Data.forEach(field => {
                                    vm.$refs.dynamicform.updateProperty(field.name, "value", "");
                                });

                                vm.$refs.dynamicform.updateProperty("ActivityId", "config.options", []);


                                vm.IsTicketMannual = 'T';
                                vm.$refs.dynamicform.updateProperty("customlineitem", "value", 'T');
                                vm.$nextTick(() => {
                                    vm.ShowInvoiceFieldData('T', vm.ticketType);

                                    if (vm.clientId) {
                                        vm.$refs.dynamicform.updateProperty("ClientId", "value", vm.clientId);
                                    }
                                    if (vm.divisionId) {
                                        vm.$refs.dynamicform.updateProperty("DivisionId", "value", vm.divisionId);
                                    }
                                    if (vm.billId) {
                                        vm.$refs.dynamicform.updateProperty("TicketNumber", "value", vm.billId);
                                    }
                                });
                                vm.GetWorkCodeData();
                                vm.$refs.dynamicform.UpdateKeyValue();
                            }


                        }

                    }
                    vm.$parent.loadLineItems();
                } else if (response.data && response.data.msgFor === "invalid") {
                    if (response.data.invalidKey) {
                        response.data.invalidKey.forEach(function (ctr) {
                            vm.$refs.dynamicform.showError(ctr.ctrId, ctr.ctrMsg);
                        });
                    }
                    vm.ShowAlert(response.data.msg, "failure", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert(response.data.msg || vm.$t("ErrorWhileProcessingRequest"), response.data.msgFor || "failure", true, vm.$t("Alert"));
                }
            }).catch(() => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), "failure", true, vm.$t("Alert"));
            });
        },
        UpdateChangedValues(formfields) {
            var vm = this;
            var data = "{";
            for (var key in formfields) {
                if (formfields[key] !== (vm.oldValues && vm.oldValues[key])) {
                    data += '"' + key + '":' + JSON.stringify(formfields[key]) + ",";
                }
            }
            if (data === "{") {
                vm.$refs.dynamicform.updateProperty("Comment", "value", "");
            } else {
                data = data.substr(0, data.length - 1) + "}";
                vm.$refs.dynamicform.updateProperty("Comment", "value", data);
            }
        },
        MakeJsonForProcessLog(formfields) {
            var vm = this;
            var dataArray = [];
            for (var key in formfields) {
                if (formfields[key] !== (vm.oldValues && vm.oldValues[key]) && key !== "Comment") {
                    dataArray.push({
                        ControlName: key,
                        OldData: (vm.oldValues && vm.oldValues[key]) || "",
                        NewData: formfields[key] || ""
                    });
                }
            }
            return dataArray;
        },
        onWorkCodeChange: function (x, y, z) {

            var vm = this;
            var url = `clientId=${vm.clientId}&workCodeId=${y.value}&divisionId=${vm.divisionId}`;
            locateBillingService.LoadRateByWorkCode(url).then(response => {
                if (response.data) {
                    var rate = parseFloat(response.data[0].WORK_RATE).toFixed(2);
                    if (vm.IsTicketMannual === 'M') {
                        vm.$refs.dynamicform.updateProperty("UnitRate", "value", rate);
                        vm.calculateNetTotalManual();
                    } else {
                        vm.$refs.dynamicform.updateProperty("UnitAmountTotal", "value", rate);
                        vm.calculateNetTotal();
                    }
                }
            });
        },
        onAdderNameChange: function (value) {
            // Handle adder name change if needed
        },
        onCustomLineItemChange: function (value, x) {
            var vm = this;
            // Handle both single value and object parameter formats
            var selectedValue = value;
            if (x && x.value) {
                selectedValue = x.value;
            } else if (typeof value === 'object' && value.value) {
                selectedValue = value.value;
            } else if (typeof value === 'string') {
                selectedValue = value;
            }

            vm.IsTicketMannual = selectedValue;
            vm.isTicketManual = selectedValue;

            // Update the radio button value in the form
            if (vm.$refs.dynamicform) {
                vm.$refs.dynamicform.updateProperty("customlineitem", "value", selectedValue);
            }

            // Show/hide fields based on selection
            vm.$nextTick(() => {
                vm.ShowInvoiceFieldData(selectedValue, vm.ticketType);
            });
        },
        updateButtonVisibility: function () {
            debugger
            var vm = this;
            var isManual = vm.IsTicketMannual === 'M' || vm.ticketType === 'F';
            var saveNewBtn = vm.buttons.find(b => b.text && b.text.includes('Save & New'));
            var saveReprocessBtn = vm.buttons.find(b => b.text && b.text.includes('Save And Reprocess'));

            // if (saveNewBtn) {
            //     saveNewBtn.visibility = !isManual && vm.billId > 0 && (vm.columnId == 0 || vm.columnId == null);
            // }

            //    if (saveReprocessBtn) {
            //         saveReprocessBtn.visibility = !isManual;
            //     }
            vm.buttons = vm.buttons.map(btn => {
                if (btn.text && btn.text.includes('Save And Reprocess')) {
                    return {
                        ...btn,
                        class: isManual
                            ? `${btn.class} d-none`
                            : btn.class.replace(/\bd-none\b/g, '').trim()
                    };
                }
                return btn;
            });

            // Update form buttons if dynamicform supports it
            if (vm.$refs.dynamicform && vm.$refs.dynamicform.updateButtons) {
                vm.$refs.dynamicform.updateButtons(vm.buttons);
            }
        },
        ShowInvoiceFieldData: function (val, ticketType) {

            var vm = this;
            if (!vm.$refs.dynamicform) {
                return;
            }

            var isManual = val === 'M' || ticketType === 'F';

            // Update IsTicketMannual
            vm.IsTicketMannual = val;

            // Update button visibility
            vm.updateButtonVisibility();

            if (isManual) {
                // Show manual fields, hide ticket fields
                vm.$refs.dynamicform.updateProperty("UnitRate", "visibility", true);
                vm.$refs.dynamicform.updateProperty("UnitQuantity", "visibility", true);
                vm.$refs.dynamicform.updateProperty("NetTotalManual", "visibility", true);

                // Re-bind event handlers for manual calculation
                var unitRateField = vm.FormSchema[0].Data.find(f => f.name === "UnitRate");
                if (unitRateField) {
                    unitRateField.onKeyUp = vm.calculateNetTotalManual;
                    unitRateField.onInput = vm.calculateNetTotalManual;
                    unitRateField.onChange = vm.calculateNetTotalManual;
                    if (!unitRateField.config) {
                        unitRateField.config = {};
                    }
                    unitRateField.config.onKeyUp = vm.calculateNetTotalManual;
                    unitRateField.config.onInput = vm.calculateNetTotalManual;
                    unitRateField.config.onChange = vm.calculateNetTotalManual;
                }

                var unitQuantityField = vm.FormSchema[0].Data.find(f => f.name === "UnitQuantity");
                if (unitQuantityField) {
                    unitQuantityField.onKeyUp = vm.calculateNetTotalManual;
                    unitQuantityField.onInput = vm.calculateNetTotalManual;
                    unitQuantityField.onChange = vm.calculateNetTotalManual;
                    if (!unitQuantityField.config) {
                        unitQuantityField.config = {};
                    }
                    unitQuantityField.config.onKeyUp = vm.calculateNetTotalManual;
                    unitQuantityField.config.onInput = vm.calculateNetTotalManual;
                    unitQuantityField.config.onChange = vm.calculateNetTotalManual;
                }

                // Show billing fields for manual mode
                vm.$refs.dynamicform.updateProperty("DistrictCode", "visibility", true);
                vm.$refs.dynamicform.updateProperty("WorkCodeId", "visibility", true);
                vm.$refs.dynamicform.updateProperty("DivisionId", "visibility", true);
                vm.$refs.dynamicform.updateProperty("TermCode", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderUnitCost", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderUnit", "visibility", true);
                vm.$refs.dynamicform.updateProperty("NetTotal", "visibility", true);

                // Hide ticket-specific fields
                var ticketFields = ["Description", "TicketId", "LocatorName", "StreetName", "FeedName",
                    "TransmissionId", "TicketType", "WorkArea", "CallDate", "TransmitDate", "LocatorStartDate",
                    "ParseDate", "County", "State", "CallerName", "CallerPhone", "WorkDoneFor", "Excavator",
                    "TypeOfWork", "LocatorEndDate", "InitialStatusDate", "LegalDuedate", "TicketStartDate",
                    "UtilityName", "FeetLocated", "MinutesWorked", "Emergency", "TicketImage", "UtilityId", "SbaId",
                    "TicketNumber", "ActivityId", "StatusCode", "ClientId", "Comment"];
                ticketFields.forEach(field => {
                    vm.$refs.dynamicform.updateProperty(field, "visibility", false);
                });

                // Disable fields
                vm.$refs.dynamicform.updateProperty("TicketNumber", "disabled", true);
                vm.$refs.dynamicform.updateProperty("ActivityId", "disabled", true);
                vm.$refs.dynamicform.updateProperty("StatusCode", "disabled", true);
                vm.$refs.dynamicform.updateProperty("TicketType", "disabled", true);
                vm.$refs.dynamicform.updateProperty("UtilityId", "disabled", true);
                vm.$refs.dynamicform.updateProperty("SbaId", "disabled", true);
                vm.$refs.dynamicform.updateProperty("DivisionId", "disabled", true); // Read-only
                vm.$refs.dynamicform.updateProperty("DistrictCode", "disabled", false); // Enabled
                vm.$refs.dynamicform.updateProperty("WorkCodeId", "disabled", ticketType === 'F');
                vm.$refs.dynamicform.updateProperty("UnitRate", "disabled", false); // Enabled
                vm.$refs.dynamicform.updateProperty("UnitQuantity", "disabled", false); // Enabled
                vm.$refs.dynamicform.updateProperty("NetTotalManual", "disabled", true); // Read-only
                vm.$refs.dynamicform.updateProperty("TermCode", "disabled", false); // Enabled
                vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "disabled", true); // Read-only (greyed out)
                vm.$refs.dynamicform.updateProperty("AdderUnitCost", "disabled", true); // Enabled
                vm.$refs.dynamicform.updateProperty("AdderUnit", "disabled", true); // Read-only
                vm.$refs.dynamicform.updateProperty("NetTotal", "disabled", true); // Read-only

                if (ticketType === 'F') {
                    vm.$refs.dynamicform.updateProperty("UnitQuantity", "visibility", false);
                    vm.$refs.dynamicform.updateProperty("NetTotalManual", "visibility", false);
                }
            } else {
                // Show ticket fields, hide manual fields
                vm.$refs.dynamicform.updateProperty("UnitRate", "visibility", false);
                vm.$refs.dynamicform.updateProperty("UnitQuantity", "visibility", false);
                vm.$refs.dynamicform.updateProperty("NetTotalManual", "visibility", false);

                // Show ticket-specific fields
                var ticketFields = ["Description", "TicketId", "LocatorName", "StreetName", "FeedName",
                    "TransmissionId", "TicketType", "WorkArea", "CallDate", "TransmitDate", "LocatorStartDate",
                    "ParseDate", "County", "State", "CallerName", "CallerPhone", "WorkDoneFor", "Excavator",
                    "TypeOfWork", "LocatorEndDate", "InitialStatusDate", "LegalDuedate", "TicketStartDate",
                    "UtilityName", "FeetLocated", "MinutesWorked", "Emergency", "TicketImage", "UtilityId", "SbaId",
                    "TicketNumber", "ActivityId", "StatusCode", "ClientId", "Comment"];
                ticketFields.forEach(field => {
                    vm.$refs.dynamicform.updateProperty(field, "visibility", true);
                });

                // Show billing fields for ticket mode
                vm.$refs.dynamicform.updateProperty("DistrictCode", "visibility", true);
                vm.$refs.dynamicform.updateProperty("WorkCodeId", "visibility", true);
                vm.$refs.dynamicform.updateProperty("DivisionId", "visibility", true);
                vm.$refs.dynamicform.updateProperty("TermCode", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderUnitCost", "visibility", true);
                vm.$refs.dynamicform.updateProperty("AdderUnit", "visibility", true);
                vm.$refs.dynamicform.updateProperty("NetTotal", "visibility", true);

                // Enable/disable based on edit mode
                if (vm.columnId > 0) {
                    // Edit mode: TicketNumber and ActivityId are disabled
                    vm.$refs.dynamicform.updateProperty("TicketNumber", "disabled", true);
                    vm.$refs.dynamicform.updateProperty("ActivityId", "disabled", true);
                    vm.$refs.dynamicform.updateProperty("StatusCode", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("TicketType", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("UtilityId", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("SbaId", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("DivisionId", "disabled", true);
                } else {
                    // Add mode: All enabled
                    vm.$refs.dynamicform.updateProperty("TicketNumber", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("ActivityId", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("StatusCode", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("TicketType", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("UtilityId", "disabled", true);
                    vm.$refs.dynamicform.updateProperty("SbaId", "disabled", false);
                    vm.$refs.dynamicform.updateProperty("DivisionId", "disabled", true);

                }

                // Enable adder fields if AdderUnit > 0
                if (vm.AdderUnit > 0) {
                    vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "disabled", true);
                    vm.$refs.dynamicform.updateProperty("AdderUnitCost", "disabled", true);
                } else {
                    vm.$refs.dynamicform.updateProperty("AdderNameLineItem", "disabled", true);
                    vm.$refs.dynamicform.updateProperty("AdderUnitCost", "disabled", true);
                }
            }

            // Force update the form to reflect changes
            vm.$refs.dynamicform.UpdateKeyValue();

            // Wait for DOM update and then force re-render and re-bind handlers
            vm.$nextTick(() => {
                if (vm.$refs.dynamicform && vm.$refs.dynamicform.UpdateKeyValue) {
                    // Re-bind event handlers after DOM update
                    if (isManual) {
                        var unitRateField = vm.FormSchema[0].Data.find(f => f.name === "UnitRate");
                        if (unitRateField) {
                            unitRateField.onKeyUp = vm.calculateNetTotalManual;
                            unitRateField.onInput = vm.calculateNetTotalManual;
                            unitRateField.onChange = vm.calculateNetTotalManual;
                            if (!unitRateField.config) {
                                unitRateField.config = {};
                            }
                            unitRateField.config.onKeyUp = vm.calculateNetTotalManual;
                            unitRateField.config.onInput = vm.calculateNetTotalManual;
                            unitRateField.config.onChange = vm.calculateNetTotalManual;
                        }

                        var unitQuantityField = vm.FormSchema[0].Data.find(f => f.name === "UnitQuantity");
                        if (unitQuantityField) {
                            unitQuantityField.onKeyUp = vm.calculateNetTotalManual;
                            unitQuantityField.onInput = vm.calculateNetTotalManual;
                            unitQuantityField.onChange = vm.calculateNetTotalManual;
                            if (!unitQuantityField.config) {
                                unitQuantityField.config = {};
                            }
                            unitQuantityField.config.onKeyUp = vm.calculateNetTotalManual;
                            unitQuantityField.config.onInput = vm.calculateNetTotalManual;
                            unitQuantityField.config.onChange = vm.calculateNetTotalManual;
                        }
                    }
                    vm.$refs.dynamicform.UpdateKeyValue();
                }
            });
        },
        onSelectionChange: function (value, x) {
            var vm = this;
            if (x && x.length > 0) {
                var clientId = Array.isArray(x) ? x[0] : x;
                vm.clientId = clientId;
                vm.GetDivisionDropdownData();
                vm.LoadAdditionalInfoByClientId();
            }
        },
        calculateNetTotal: function () {
            // Calculate net total
        },
        calculateNetTotalManual: function (event) {
            var vm = this;
            // Use setTimeout to ensure the value is updated in the form
            setTimeout(function () {
                if (!vm.$refs.dynamicform) {
                    return;
                }

                var unitRateStr = vm.$refs.dynamicform.getPropertyValue("UnitRate", "value") || "0";
                var unitQuantityStr = vm.$refs.dynamicform.getPropertyValue("UnitQuantity", "value") || "0";

                // Remove any commas or other formatting
                unitRateStr = unitRateStr.toString().replace(/,/g, '').trim();
                unitQuantityStr = unitQuantityStr.toString().replace(/,/g, '').trim();

                // Handle empty strings
                if (unitRateStr === '' || unitRateStr === null || unitRateStr === undefined) {
                    unitRateStr = "0";
                }
                if (unitQuantityStr === '' || unitQuantityStr === null || unitQuantityStr === undefined) {
                    unitQuantityStr = "0";
                }

                var unitRate = parseFloat(unitRateStr) || 0;
                var unitQuantity = parseFloat(unitQuantityStr) || 0;

                var total = unitQuantity * unitRate;
                var total1 = parseFloat(Math.round(total * 100) / 100).toFixed(2);

                if (!isNaN(total1) && total1 !== "NaN") {
                    vm.$refs.dynamicform.updateProperty("NetTotalManual", "value", total1);
                }
            }, 10);
        },
        formatDateForDisplay: function (dateValue) {
            if (!dateValue) return '';

            // If already in MM/DD/YYYY format, return as is
            if (typeof dateValue === 'string' && /^\d{2}\/\d{2}\/\d{4}$/.test(dateValue)) {
                return dateValue;
            }

            // Handle Date object
            var d;
            if (dateValue instanceof Date) {
                d = dateValue;
            } else if (typeof dateValue === 'string') {
                // Try parsing different date formats
                // First try ISO format (YYYY-MM-DD)
                if (/^\d{4}-\d{2}-\d{2}/.test(dateValue)) {
                    var parts = dateValue.split('T')[0].split('-');
                    d = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
                } else {
                    d = new Date(dateValue);
                    if (isNaN(d.getTime())) {
                        // Try parsing MM/DD/YYYY format
                        var parts2 = dateValue.split('/');
                        if (parts2.length === 3) {
                            d = new Date(parseInt(parts2[2]), parseInt(parts2[0]) - 1, parseInt(parts2[1]));
                        }
                    }
                }
            } else {
                d = new Date(dateValue);
            }

            if (isNaN(d.getTime())) {
                return dateValue; // Return original if can't parse
            }

            var month = (d.getMonth() + 1).toString().padStart(2, '0');
            var day = d.getDate().toString().padStart(2, '0');
            var year = d.getFullYear();
            return month + '/' + day + '/' + year;
        },
        viewTicketImage: function () {
            debugger
            var vm = this;
            vm.IsViewTicket = true;
            var TicketNumber = vm.$refs.dynamicform ? vm.$refs.dynamicform.getPropertyValue("TicketNumber", "value") : '';

            var TransmissionId = vm.$refs.dynamicform ? vm.$refs.dynamicform.getPropertyValue("TransmissionId", "value") : '';

            var url = `TicketNumber=${TicketNumber}&TransmissionId=${TransmissionId}`;
            locateBillingService.ViewTicketImage(url).then(response => {
                if (response.data && response.data.length > 0) {
                    vm.TicketContent = response.data[0].RAW_IMAGE;
                }
            });
        },
        CloseTemplate: function () {
            this.IsViewTicket = false;
        },
    }
}
